tool_calls:
awk -F',' '
NR==1 {
    # Parse header row
    for (i=1; i<=NF; i++) {
        header[i] = $i
    }
    next
}
{
    # Build object for each row
    if (NR==2) print "["
    else print ","

    printf "  {"
    for (i=1; i<=NF; i++) {
        if (i>1) printf ", "
        printf "\"%s\": \"%s\"", header[i], $i
    }
    printf "}"
}
END {
    if (NR>1) print "\n]"
}
' /data/users.csv

